import json, pathlib, re
root=pathlib.Path('benchmarks/sigma_xxx_finite_gamma_replay')
pats=[re.compile('/'+'Users'+'/'), re.compile(r'github_pat_[A-Za-z0-9_]{20,}'), re.compile(r'ghp_[A-Za-z0-9]{20,}'), re.compile(r'BEGIN (RSA|OPENSSH|DSA|EC|PGP) PRIVATE KEY'), re.compile(r'api[_-]?key\s*[:=]', re.I), re.compile('sec'+'ret'+r'\s*[:=]', re.I), re.compile('pass'+'word'+r'\s*[:=]', re.I), re.compile('coo'+'kie'+r'\s*[:=]', re.I)]
hits=[]
for p in sorted(root.rglob('*')):
    if not p.is_file() or '__pycache__' in p.parts or p.suffix in {'.pyc','.pyo'}:
        continue
    try:
        text=p.read_text()
    except UnicodeDecodeError:
        continue
    for pat in pats:
        if pat.search(text):
            hits.append(str(p))
print(json.dumps({'hits':hits,'passed':not hits}, indent=2))
raise SystemExit(0 if not hits else 1)
